struct IndexVectorHash {
  std::size_t operator()(const std::vector<Eigen::Index>& v) const noexcept {
    std::size_t seed = 0;
    for (Eigen::Index idx : v) {
      seed ^= std::hash<Eigen::Index>{}(idx) + 0x9e3779b9 + (seed << 6) + (seed >> 2);
    }
    return seed;
  }
};

